kens&quot;:[],&quot;OutputTokenName&quot;:&quot;myuserdetails&quot;,&quot;ExtractColumns&quot;:[{&quot;name&quot;:&quot;username&quot;,&quot;value&quot;:&quot;username&quot;},{&quot;name&quot;:&quot;email&quot;,&quot;value&quot;:&quot;email&quot;}]},&quot;$_isOpen&quot;:false,&quot;$_uid&quot;:&quot;action16910719141093308&quot;,&quot;EventName&quot;:&quot;click&quot;,&quot;Definition&quot;:{&quot;Id&quot;:&quot;RunSql&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;Run SQL Query&quot;},&quot;HelpText&quot;:{&quot;default&quot;:&quot;Executes the specified SQL query, optionally storing the output for use in other actions.&quot;},&quot;TypeStr&quot;:&quot;DnnSharp.Common.Actions.Data.ExecuteSql, DnnSharp.Common.Actions&quot;,&quot;Final&quot;:false,&quot;IsClientAction&quot;:false,&quot;Groups&quot;:[],&quot;Parameters&quot;:[{&quot;For&quot;:null,&quot;NotFor&quot;:null,&quot;Id&quot;:&quot;DbConnector&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;Database&quot;},&quot;HelpText&quot;:null,&quot;Placeholder&quot;:null,&quot;DefaultValue&quot;:null,&quot;Default&quot;:null,&quot;Type&quot;:&quot;ActionCredentials&quot;,&quot;IsPublic&quot;:false,&quot;Settings&quot;:{&quot;Selection&quot;:&quot;Single&quot;,&quot;Type&quot;:&quot;Database&quot;},&quot;Validation&quot;:[],&quot;Groups&quot;:null,&quot;Parameters&quot;:[],&quot;Conditions&quot;:[{&quot;TypeStr&quot;:&quot;DnnSharp.Common2.Services.PlantAnApp.ConfigConditions.IsPlantAnApp,DnnSharp.Common2&quot;,&quot;Settings&quot;:{}}]},{&quot;For&quot;:null,&quot;NotFor&quot;:null,&quot;Id&quot;:&quot;ConnectionString&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;Override Connection String&quot;},&quot;HelpText&quot;:{&quot;default&quot;:&quot;By default, the SQL will run against the built-in database or the selected Connection. Use this field to override the connection string. Also supports the name of a connection string from the web.config. It will respect the Provider (ODBC, SqlClient, etc.). Can contain Tokens. Read more about &amp;lt;a href=\&quot;http://www.connectionstrings.com/\&quot; target=\&quot;_blank\&quot;&amp;gt;supported formats&amp;lt;/a&amp;gt;.&quot;},&quot;Placeholder&quot;:null,&quot;DefaultValue&quot;:null,&quot;Default&quot;:null,&quot;Type&quot;:&quot;Text&quot;,&quot;IsPublic&quot;:false,&quot;Settings&quot;:{},&quot;Validation&quot;:[],&quot;Groups&quot;:null,&quot;Parameters&quot;:[],&quot;Conditions&quot;:[]},{&quot;For&quot;:null,&quot;NotFor&quot;:null,&quot;Id&quot;:&quot;QueryTimeout&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;Query Timeout&quot;},&quot;HelpText&quot;:{&quot;default&quot;:&quot;Set a time in seconds after which a query will time out. The default is set 10 minutes or 600 seconds also this parameter can&#39;t be negative or under 10 seconds. Can contain Tokens. &quot;},&quot;Placeholder&quot;:null,&quot;DefaultValue&quot;:null,&quot;Default&quot;:null,&quot;Type&quot;:&quot;Text&quot;,&quot;IsPublic&quot;:false,&quot;Settings&quot;:{},&quot;Validation&quot;:[],&quot;Groups&quot;:null,&quot;Parameters&quot;:[],&quot;Conditions&quot;:[]},{&quot;For&quot;:null,&quot;NotFor&quot;:null,&quot;Id&quot;:&quot;SqlQuery&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;SQL Query&quot;},&quot;HelpText&quot;:{&quot;default&quot;:&quot;SQL to execute. Can contain Tokens. &amp;lt;br/&amp;gt; &amp;lt;div style=\&quot;color:red\&quot;&amp;gt;WARNING!&amp;lt;/div&amp;gt; We encourage using binding parameters instead of using the tokens directly on sql query. Just use @param instead of [token] and bind below values as shown: Parameter Name: param ; Parameter Value: [token]. This will keep your database safe.&amp;lt;br/&amp;gt;&quot;},&quot;Placeholder&quot;:null,&quot;DefaultValue&quot;:null,&quot;Default&quot;:null,&quot;Type&quot;:&quot;Code&quot;,&quot;IsPublic&quot;:false,&quot;Settings&quot;:{&quot;CodeMirrorMode&quot;:&quot;sql&quot;,&quot;AiAssist&quot;:&quot;sql&quot;},&quot;Validation&quot;:[{&quot;Type&quot;:&quot;Required&quot;,&quot;From&quot;:null,&quot;For&quot;:null,&quot;Settings&quot;:{}}],&quot;Groups&quot;:null,&quot;Parameters&quot;:[],&quot;Conditions&quot;:[]},{&quot;For&quot;:null,&quot;NotFor&quot;:null,&quot;Id&quot;:&quot;BindTokens&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;Bind Tokens&quot;},&quot;HelpText&quot;:{&quot;default&quot;:&quot;Bind the parameters above with a value or token. e.g. P. Name:param, P. Value:[token] &quot;},&quot;Placeholder&quot;:null,&quot;DefaultValue&quot;:null,&quot;Default&quot;:null,&quot;Type&quot;:&quot;NameValueCollection&quot;,&quot;IsPublic&quot;:false,&quot;Settings&quot;:{&quot;NameColumn&quot;:&quot;Parameter Name&quot;,&quot;ValueColumn&quot;:&quot;Parameter Value&quot;,&quot;ButtonName&quot;:&quot;Bind more data&quot;},&quot;Validation&quot;:[],&quot;Groups&quot;:null,&quot;Parameters&quot;:[],&quot;Conditions&quot;:[]},{&quot;For&quot;:null,&quot;NotFor&quot;:null,&quot;Id&quot;:&quot;OutputTokenName&quot;,&quot;Title&quot;:{&quot;default&quot;:&quot;Store Result&quot;},&quot;HelpText&quot;:{&quot;default&quot;:&quot;Optionally, provide a token name that will store the result. For example, store IDs generated by inserts or select data that is needed by other actions. If the query returns more than one column, you can access them using [&amp;amp;lt;OutputTokenName&amp;amp;gt;:&amp;amp;lt;ColumnName&amp;amp;gt;] syntax. Date fields generate additional tokens - [&amp;amp;lt;OutputTokenName&amp;amp;gt;:&amp;amp;lt;ColumnName&amp;amp;gt;:ISO], [&amp;amp;lt;OutputTokenName&amp;amp;gt;:&amp;amp;lt;ColumnName&amp;amp;gt;:ISODate], [&amp;amp;lt;OutputTokenName&amp;amp;gt;:&amp;amp;lt;ColumnName&amp;amp;gt;:ISOAsUtc].&quot;},&quot;Placeholder&quot;:null,&quot;DefaultValue&quot;:null,&quot;Default&quot;:null,&quot;Type&quot;:&quot;Text&quot;,&quot;IsPublic&quot;:false,&quot;Settings&quot;:{},&quot;Validation&quot;:[],&quot;Groups&quot;:null,&quot;Parameters&quot;:[],&quot;Conditions&quot;:[]},{&quot;For&quot;:null,&quot;NotF